// Node.js specific functionality for pdfdiff
// Adds file system support on top of the browser-first core

import { readFile } from 'fs/promises';
import { compareTexts, formatDiff } from './core.js';
import { extractPdfText as extractPdfTextWithPdfjs } from './utils/pdfjs-extractor.js';

/**
 * Extract text from a PDF file or buffer (Node.js version with fs support)
 * @param {string|Buffer} pdfPath - Path to PDF file or Buffer containing PDF data
 * @returns {Promise<string>} Extracted text content
 */
export async function extractPdfText(pdfPath) {
  try {
    let pdfBuffer;
    
    if (typeof pdfPath === 'string') {
      pdfBuffer = await readFile(pdfPath);
    } else if (Buffer.isBuffer(pdfPath)) {
      pdfBuffer = pdfPath;
    } else {
      throw new Error('Invalid input: expected file path string or Buffer');
    }
    
    return await extractPdfTextWithPdfjs(new Uint8Array(pdfBuffer));
  } catch (error) {
    throw new Error(`Failed to extract text from PDF: ${error.message}`);
  }
}

/**
 * Compare two PDF files and return differences (Node.js version with fs support)
 * @param {string|Buffer} pdf1 - First PDF file path or Buffer
 * @param {string|Buffer} pdf2 - Second PDF file path or Buffer
 * @param {import('./types.js').CompareOptions} [options] - Comparison options
 * @returns {Promise<import('./types.js').DiffResult>} Comparison result
 */
export async function comparePdfs(pdf1, pdf2, options = {}) {
  const { ignoreWhitespace = false, ignoreCase = false, mode = 'char' } = options;
  
  try {
    const text1 = await extractPdfText(pdf1);
    const text2 = await extractPdfText(pdf2);
    
    return compareTexts(text1, text2, { ignoreWhitespace, ignoreCase, mode });
  } catch (error) {
    throw new Error(`Failed to compare PDFs: ${error.message}`);
  }
}

// Re-export browser-compatible functions
export { compareTexts, formatDiff };